package com.DecisionMakingStatement;

public class If_Else {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a = 5;
		int b = 6;
		if(a > b) {
			system.out.println("a is greater than b");
		}
		else {
			System.out.println("b is greater than a");
		}
	}

}
